# ============================================================
#  转换
# ============================================================
acc_arr = np.array(acc, dtype=np.float64) * 100        # (20,)  → 百分比
lengths_arr = np.array(token_lengths, dtype=np.float64)  # (20,)
density_arr = np.array(density_matrix, dtype=np.float64)  # (32, 20)

num_layers, num_steps = density_arr.shape
steps = np.arange(1, num_steps + 1)  # 1 ~ 20

# ============================================================
#  Plot 1 — Token Length vs Accuracy 折线图
# ============================================================
fig1, ax1 = plt.subplots(figsize=(7, 4.5))

ax1.plot(lengths_arr, acc_arr, marker="o", linewidth=2, markersize=5,
         color="#2563EB", markeredgecolor="white", markeredgewidth=1.2,
         zorder=3)
ax1.fill_between(lengths_arr, acc_arr, alpha=0.08, color="#2563EB")

ax1.set_xlabel("Memory Length (tokens)")
ax1.set_ylabel("Accuracy")
ax1.set_xlim(lengths_arr[0] - 200, lengths_arr[-1] + 200)
ax1.set_ylim(0, max(acc_arr) * 1.12)
ax1.yaxis.set_major_formatter(FuncFormatter(lambda y, _: f"{y:.0f}%"))
ax1.grid(True, axis="both", linestyle="--")

# 只标注首、中、末几个关键点，避免拥挤
key_indices = [4, 9, 14, 19]
for s_idx in key_indices:
    ax1.annotate(
        f"$n$={s_idx + 1}",
        (lengths_arr[s_idx], acc_arr[s_idx]),
        textcoords="offset points",
        xytext=(0, 10),
        fontsize=18,
        ha="center",
        color="#555555",
    )

fig1.tight_layout()
fig1.savefig("plot_figures/plot1_acc_vs_length.pdf")
print("[✓] Saved: plot1_acc_vs_length.pdf")

# ============================================================
#  Plot 2 — Attention Density 热力图 (Layer × Step)
# ============================================================
fig2, ax2 = plt.subplots(figsize=(10, 7))

# 使用 LogNorm 以更好地区分小数量级之间的差异
vmin = max(density_arr.min(), 1e-7)
vmax = density_arr.max()
norm = mcolors.LogNorm(vmin=vmin, vmax=vmax)

# 使用 pcolormesh 绘制离散格子（每格分明，无插值）
# 配色：浅色 → 深红（经典热力图配色）
im = ax2.pcolormesh(
    density_arr, cmap="YlOrRd", norm=norm,
    edgecolors="white", linewidth=0.5,
)

ax2.set_xlabel("Time Step ($n$)")
ax2.set_ylabel("Layer Index ($l$)")

# X 轴: step 编号标在每格中心
ax2.set_xticks(np.arange(num_steps) + 0.5)
ax2.set_xticklabels([str(s) for s in range(1, num_steps + 1)], fontsize=18)

# Y 轴: 每隔 2 层标一次，标在格子中心
ax2.set_yticks(np.arange(0, num_layers, 2) + 0.5)
ax2.set_yticklabels([str(l) for l in range(0, num_layers, 2)], fontsize=18)

# 翻转 Y 轴使 layer 0 在顶部
ax2.invert_yaxis()

# Colorbar
cbar = fig2.colorbar(im, ax=ax2, fraction=0.03, pad=0.03, format=ticker.LogFormatterSciNotation())
cbar.set_label("Attention Density", fontsize=18)
cbar.ax.tick_params(labelsize=9)

# 恢复四边框（热力图需要完整边框）
for spine in ax2.spines.values():
    spine.set_visible(True)
    spine.set_linewidth(0.5)

fig2.tight_layout()
fig2.savefig("plot_figures/plot2_density_heatmap.pdf")
print("[✓] Saved: plot2_density_heatmap.pdf")

# ============================================================
#  Plot 3 — 每层 Density 与 Accuracy 的相关性
# ============================================================

# 两种方法（去除 Kendall）
methods = {
    "Pearson":  lambda x, y: stats.pearsonr(x, y),
    "Spearman": lambda x, y: stats.spearmanr(x, y),
}

# 结果存储
corr_results = {name: {"r": [], "p": []} for name in methods}

for l in range(num_layers):
    layer_density = density_arr[l]  # (20,)
    for name, func in methods.items():
        r_val, p_val = func(layer_density, acc_arr)
        corr_results[name]["r"].append(r_val)
        corr_results[name]["p"].append(p_val)

# 打印表格
print("\n" + "=" * 80)
print("Correlation between per-layer Density and Accuracy (across 20 steps)")
print("=" * 80)
header = f"{'Layer':>6}"
for name in methods:
    header += f" | {name + ' r':>12} {name + ' p':>12}"
print(header)
print("-" * len(header))

for l in range(num_layers):
    row = f"{l:>6}"
    for name in methods:
        r = corr_results[name]["r"][l]
        p = corr_results[name]["p"][l]
        row += f" | {r:>12.6f} {p:>12.6f}"
    print(row)

# ---- 绘制相关性柱状图 ----
fig3, axes = plt.subplots(1, 2, figsize=(11, 4.5), sharey=True)
palette = {
    "Pearson":  {"face": "#4C78A8", "edge": "#375E82"},
    "Spearman": {"face": "#E45756", "edge": "#B8403F"},
}

for ax, (name, data) in zip(axes, corr_results.items()):
    r_vals = np.array(data["r"])
    p_vals = np.array(data["p"])
    layers = np.arange(num_layers)

    bars = ax.bar(
        layers, r_vals, width=0.78,
        color=palette[name]["face"], edgecolor=palette[name]["edge"],
        linewidth=0.6, alpha=0.85, zorder=2,
    )

    ax.set_xlabel("Layer")
    ax.set_title(name, fontweight="semibold")
    ax.axhline(0, color="#888888", linewidth=0.6, linestyle="-", zorder=1)
    ax.set_xticks(np.arange(0, num_layers, 4))
    ax.grid(axis="y", linestyle="--")
    ax.set_xlim(-0.8, num_layers - 0.2)

axes[0].set_ylabel("Correlation Coefficient ($r$)")

fig3.tight_layout(w_pad=1.5)
fig3.savefig("plot_figures/plot3_correlation.pdf")
print("\n[✓] Saved: plot3_correlation.pdf")

# ---- 汇总：哪些层相关性最强 ----
print("\n" + "=" * 60)
print("Top-5 layers by |Pearson r|:")
print("=" * 60)
pearson_r = np.array(corr_results["Pearson"]["r"])
top5 = np.argsort(np.abs(pearson_r))[::-1][:5]
for rank, l in enumerate(top5, 1):
    print(f"  #{rank}  Layer {l:2d}  r = {pearson_r[l]:+.6f}  p = {corr_results['Pearson']['p'][l]:.2e}")

# ============================================================
#  Plot 4 — Accuracy vs Layer-13 Attention Density (双 Y 轴)
# ============================================================
TARGET_LAYER = 13
layer_density = density_arr[TARGET_LAYER]  # (20,)

fig4, ax4_left = plt.subplots(figsize=(7.5, 4.5))

# --- 左轴：Accuracy（与 Plot 1 保持一致的风格） ---
color_acc = "#2563EB"
l_acc, = ax4_left.plot(
    lengths_arr, acc_arr,
    marker="o", linewidth=2, markersize=5,
    color=color_acc, markeredgecolor="white", markeredgewidth=1.2,
    zorder=3, label="Accuracy",
)
ax4_left.fill_between(lengths_arr, acc_arr, alpha=0.08, color=color_acc)

ax4_left.set_xlabel("Memory Length (tokens)")
ax4_left.set_ylabel("Accuracy", color=color_acc)
ax4_left.tick_params(axis="y", colors=color_acc)
ax4_left.yaxis.set_major_formatter(FuncFormatter(lambda y, _: f"{y:.0f}%"))
ax4_left.set_xlim(lengths_arr[0] - 200, lengths_arr[-1] + 200)
ax4_left.set_ylim(0, max(acc_arr) * 1.12)
ax4_left.grid(True, axis="both", linestyle="--")

# --- 右轴：Layer-13 Attention Density ---
ax4_right = ax4_left.twinx()
color_den = "#D62728"
l_den, = ax4_right.plot(
    lengths_arr, layer_density,
    marker="s", linewidth=2, markersize=5,
    color=color_den, markeredgecolor="white", markeredgewidth=1.2,
    zorder=3, label=f"Attention Density (Layer {TARGET_LAYER})",
)

ax4_right.set_ylabel(
    f"Attention Density",
    color=color_den,
)
ax4_right.tick_params(axis="y", colors=color_den)
ax4_right.yaxis.set_major_formatter(ticker.ScalarFormatter(useMathText=True))
ax4_right.ticklabel_format(axis="y", style="sci", scilimits=(0, 0))

# 右轴需要保留右边 spine
ax4_right.spines["top"].set_visible(False)
ax4_right.spines["right"].set_visible(True)
ax4_right.spines["right"].set_linewidth(0.8)
ax4_right.spines["right"].set_color(color_den)
ax4_left.spines["left"].set_color(color_acc)

# 合并图例
lines = [l_acc, l_den]
ax4_left.legend(
    lines, [ln.get_label() for ln in lines],
    loc="upper right", frameon=False, fontsize=14,
)

fig4.tight_layout()
fig4.savefig("plot_figures/plot4_acc_vs_density_layer13.pdf")
print(f"\n[✓] Saved: plot4_acc_vs_density_layer13.pdf (Layer {TARGET_LAYER})")

plt.show()
